/**
 * Facts 持久化层
 * 通过 IPC 调用主进程的 yamlService，读写 facts/*.yaml 文件
 * 与命令行工具共用同一数据源
 */

export interface Fact {
  id: string
  type: 'power' | 'item' | 'relation' | 'foreshadow'
  subject: string
  object: string
  content: string
  chapterStart: number
  chapterEnd: number
  createdAt: number
}

class FactsStore {
  private projectRoot: string | null = null

  async setProjectRoot(root: string): Promise<void> {
    if (!root || typeof root !== 'string') {
      throw new Error('无效的项目根路径')
    }
    this.projectRoot = root
  }

  private factsDir(): string {
    if (!this.projectRoot) throw new Error('未设置项目根路径')
    return `${this.projectRoot}/facts`
  }

  // ─── 读取 facts（通过 IPC 调用主进程 js-yaml） ─────────────────────────────

  async loadCharactersFacts(): Promise<Record<string, unknown>> {
    try {
      const result = await window.electronAPI.yaml.read(`${this.factsDir()}/characters_facts.yaml`)
      if (result.success && result.data) return result.data as Record<string, unknown>
    } catch (e) {
      console.error('loadCharactersFacts 失败:', e)
    }
    return {}
  }

  async loadPlotFacts(): Promise<Record<string, unknown>> {
    try {
      const result = await window.electronAPI.yaml.read(`${this.factsDir()}/plot_facts.yaml`)
      if (result.success && result.data) return result.data as Record<string, unknown>
    } catch (e) {
      console.error('loadPlotFacts 失败:', e)
    }
    return {}
  }

  async loadSettingsFacts(): Promise<Record<string, unknown>> {
    try {
      const result = await window.electronAPI.yaml.read(`${this.factsDir()}/settings_facts.yaml`)
      if (result.success && result.data) return result.data as Record<string, unknown>
    } catch (e) {
      console.error('loadSettingsFacts 失败:', e)
    }
    return {}
  }

  // ─── 写入 facts（通过 IPC 调用主进程 js-yaml） ─────────────────────────────

  async appendFacts(facts: Array<{
    type: string
    subject: string
    object?: string
    content: string
    chapterStart: number
    chapterEnd: number
    confidence: number
  }>): Promise<{ success: boolean; error?: string }> {
    try {
      if (!this.projectRoot) {
        return { success: false, error: '未设置项目根路径' }
      }

      const charFacts = (await this.loadCharactersFacts()) as Record<string, Record<string, unknown>>
      const plotFacts = (await this.loadPlotFacts()) as Record<string, unknown>

      for (const fact of facts) {
        if (fact.type === 'power' || fact.type === 'item' || fact.type === 'relation') {
          if (!charFacts[fact.subject]) {
            charFacts[fact.subject] = {}
          }
          const char: Record<string, unknown> = charFacts[fact.subject]

          if (fact.type === 'power' && fact.content) {
            const abilities = (char['abilities'] as string[]) || []
            if (!abilities.includes(fact.content)) {
              abilities.push(fact.content)
              char['abilities'] = abilities
            }
          }
          if (fact.type === 'relation' && fact.object) {
            const relationships = (char['relationships'] as Record<string, string>) || {}
            relationships[fact.object] = fact.content
            char['relationships'] = relationships
          }
          if (fact.type === 'item' && fact.content) {
            const traits = (char['personality_traits'] as string[]) || []
            if (!traits.includes(fact.content)) {
              traits.push(fact.content)
              char['personality_traits'] = traits
            }
          }
        }

        if (fact.type === 'foreshadow') {
          const foreshadowList = (plotFacts['伏笔清单'] as Array<Record<string, unknown>>) || []
          const existing = foreshadowList.some(
            p => p['description'] === fact.content && p['setup_chapter'] === fact.chapterStart
          )
          if (!existing) {
            foreshadowList.push({
              id: `F${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,
              description: fact.content,
              setup_chapter: fact.chapterStart,
              status: '待回收',
              related_characters: fact.subject ? [fact.subject] : [],
            })
            plotFacts['伏笔清单'] = foreshadowList
          }
        }
      }

      const charWriteResult = await window.electronAPI.yaml.write(`${this.factsDir()}/characters_facts.yaml`, charFacts)
      if (!charWriteResult.success) {
        throw new Error(`角色事实保存失败: ${charWriteResult.error}`)
      }
      const plotWriteResult = await window.electronAPI.yaml.write(`${this.factsDir()}/plot_facts.yaml`, plotFacts)
      if (!plotWriteResult.success) {
        throw new Error(`情节事实保存失败: ${plotWriteResult.error}`)
      }

      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  }

  // ─── 读取 facts 用于 UI 显示 ─────────────────────────────────────────────

  async getFacts(
    filters?: {
      type?: string
      subject?: string
      chapter?: number
    },
    projectRootOverride?: string | null
  ): Promise<Fact[]> {
    const effectiveRoot = projectRootOverride ?? this.projectRoot
    if (!effectiveRoot) {
      throw new Error('未设置项目根路径，请先打开小说项目')
    }
    const factsDir = `${effectiveRoot}/facts`
    try {
      // 直接用 effectiveRoot 读取，不走 this.projectRoot（可能未同步）
      const charResult = await window.electronAPI.yaml.read(`${factsDir}/characters_facts.yaml`)
      const charFacts = (charResult.success && charResult.data
        ? charResult.data as Record<string, Record<string, unknown>>
        : {}) as Record<string, Record<string, unknown>>
      const plotResult = await window.electronAPI.yaml.read(`${factsDir}/plot_facts.yaml`)
      const plotFacts = (plotResult.success && plotResult.data
        ? plotResult.data as Record<string, unknown>
        : {}) as Record<string, unknown>

      const results: Fact[] = []

      // 从 characters_facts.yaml 还原 facts
      for (const [charName, char] of Object.entries(charFacts)) {
        if (char.abilities) {
          for (const ability of (char.abilities as string[]) || []) {
            results.push({
              id: `power-${charName}-${ability}`.slice(0, 64),
              type: 'power',
              subject: charName,
              object: '',
              content: ability,
              chapterStart: 1,
              chapterEnd: 9999,
              createdAt: 0,
            })
          }
        }
        if (char.relationships) {
          for (const [other, rel] of Object.entries(char.relationships as Record<string, string>)) {
            results.push({
              id: `rel-${charName}-${other}`.slice(0, 64),
              type: 'relation',
              subject: charName,
              object: other,
              content: rel,
              chapterStart: 1,
              chapterEnd: 9999,
              createdAt: 0,
            })
          }
        }
      }

      // 从 plot_facts.yaml 还原伏笔
      if (plotFacts['伏笔清单']) {
        for (const fb of (plotFacts['伏笔清单'] as Array<Record<string, unknown>>)) {
          results.push({
            id: `fb-${fb['id']}` || `fb-${Date.now()}`,
            type: 'foreshadow',
            subject: ((fb['related_characters'] as string[] || [])[0]) || '',
            object: '',
            content: String(fb['description'] || ''),
            chapterStart: Number(fb['setup_chapter'] || 1),
            chapterEnd: Number(fb['setup_chapter'] || 1),
            createdAt: 0,
          })
        }
      }

      // 过滤
      let filtered = results
      if (filters?.type && filters.type !== 'all') {
        filtered = filtered.filter(f => f.type === filters.type)
      }
      if (filters?.subject) {
        filtered = filtered.filter(
          f => f.subject === filters.subject || f.object === filters.subject
        )
      }
      if (filters?.chapter) {
        filtered = filtered.filter(
          f => f.chapterStart <= filters.chapter! && f.chapterEnd >= filters.chapter!
        )
      }

      return filtered
    } catch (e) {
      console.error('读取 facts 失败:', e)
      return []
    }
  }
}

